/**
 * Hook Visitor - AST Traversal and Code Generation
 *
 * Implements the Visitor pattern to traverse the AST generated by the parser
 * and generate TypeScript hook code
 */

import {
  BaseHookVisitor,
  type HookDefinitionNode,
  type HookType,
  type ParameterNode,
} from "./types";

/**
 * Visitor configuration options
 */
export interface VisitorOptions {
  addComments?: boolean;
  includeErrorHandling?: boolean;
  asyncHooks?: boolean;
}

/**
 * Default visitor options
 */
const DEFAULT_OPTIONS: VisitorOptions = {
  addComments: true,
  includeErrorHandling: true,
  asyncHooks: true,
};

/**
 * Code Generation Visitor
 *
 * Traverses the AST and generates TypeScript code for hooks
 */
export class HookCodeGenerationVisitor extends BaseHookVisitor<string> {
  private options: VisitorOptions;
  private currentImports: Set<string> = new Set();

  constructor(options: VisitorOptions = {}) {
    super();
    this.options = { ...DEFAULT_OPTIONS, ...options };
  }

  /**
   * Visit a hook definition node and generate code
   */
  visitHookDefinition(node: HookDefinitionNode): string {
    const { hookType, hookName, entity, parameters } = node;

    // Reset imports for each hook
    this.currentImports = new Set();
    if (this.options.asyncHooks) {
      this.currentImports.add("Promise");
    }

    // Generate the hook function
    let code = "";

    // Add header comment
    if (this.options.addComments) {
      code += this.generateHeaderComment(node);
    }

    // Generate the function signature
    code += this.generateFunctionSignature(hookType, hookName, entity, parameters);

    // Generate function body
    code += this.generateFunctionBody(hookType, hookName, entity, parameters);

    return code;
  }

  /**
   * Visit a parameter node (not used in code generation but part of visitor pattern)
   */
  visitParameter(node: ParameterNode): string {
    return node.name;
  }

  /**
   * Generate header comment for the hook
   */
  private generateHeaderComment(node: HookDefinitionNode): string {
    const { hookType, hookName, entity } = node;
    return `/**
 * ${this.formatHookName(hookType)} Hook: ${hookName}
 *
 * Hook Type: ${hookType}
 * Entity: ${entity}
 *
 * This hook is executed ${this.getExecutionDescription(hookType)} ${entity} entity.
 *
 * @generated by Hook Code Generator
 */

`;
  }

  /**
   * Generate function signature
   */
  private generateFunctionSignature(
    hookType: HookType,
    hookName: string,
    entity: string,
    _parameters?: ParameterNode[]
  ): string {
    const asyncKeyword = this.options.asyncHooks ? "async " : "";
    const paramName = this.getDataParameterName(hookType);

    let signature = `export ${asyncKeyword}function ${hookName}${entity}(`;

    // Add parameters
    const params: string[] = [];

    if (hookType.startsWith("before")) {
      // Before hooks receive data/context
      params.push(`${paramName}: ${entity}CreateInput`);
    } else if (hookType.startsWith("after")) {
      // After hooks receive the result
      params.push(`result: ${entity}`);
    } else if (hookType === "customValidate") {
      // Validation hooks receive data and return validation result
      params.push(`data: Partial<${entity}>`);
    }

    signature += params.join(", ");
    signature += "): ";

    // Add return type
    if (hookType.startsWith("before")) {
      signature += `Promise<${entity}CreateInput>`;
    } else if (hookType.startsWith("after")) {
      signature += "Promise<void>";
    } else if (hookType === "customValidate") {
      signature += "Promise<{ valid: boolean; errors?: string[] }>";
    }

    signature += " {\n";

    return signature;
  }

  /**
   * Generate function body
   */
  private generateFunctionBody(
    hookType: HookType,
    hookName: string,
    entity: string,
    parameters?: ParameterNode[]
  ): string {
    let body = "";

    // Add logging
    body += `  console.log('[${hookType}:${hookName}]', { entity: '${entity}' });\n\n`;

    // Add TODO comment
    body += `  // TODO: Implement ${hookName} logic for ${entity}\n`;

    // Add specific implementation hints based on hook type
    if (parameters && parameters.length > 0) {
      body += `  // Available parameters: ${parameters.map((p) => p.name).join(", ")}\n`;
    }

    // Add type-specific logic
    if (hookType === "beforeCreate") {
      body += this.generateBeforeCreateBody(entity);
    } else if (hookType === "afterCreate") {
      body += this.generateAfterCreateBody(entity);
    } else if (hookType === "beforeUpdate") {
      body += this.generateBeforeUpdateBody(entity);
    } else if (hookType === "afterUpdate") {
      body += this.generateAfterUpdateBody(entity);
    } else if (hookType === "beforeDelete") {
      body += this.generateBeforeDeleteBody(entity);
    } else if (hookType === "afterDelete") {
      body += this.generateAfterDeleteBody(entity);
    } else if (hookType === "beforeRead") {
      body += this.generateBeforeReadBody(entity);
    } else if (hookType === "afterRead") {
      body += this.generateAfterReadBody(entity);
    } else if (hookType === "beforeList") {
      body += this.generateBeforeListBody(entity);
    } else if (hookType === "afterList") {
      body += this.generateAfterListBody(entity);
    } else if (hookType === "customValidate") {
      body += this.generateValidationBody(entity);
    }

    // Add return statement
    body += "\n" + this.generateReturnStatement(hookType, entity);

    body += "}\n";

    return body;
  }

  /**
   * Generate beforeCreate specific logic
   */
  private generateBeforeCreateBody(entity: string): string {
    return `  // Modify data before creating ${entity}
  // Example: Hash password, generate slug, set defaults

  const modifiedData = { ...data };

  // Your modification logic here

  return modifiedData;`;
  }

  /**
   * Generate afterCreate specific logic
   */
  private generateAfterCreateBody(entity: string): string {
    return `  // Perform actions after ${entity} creation
  // Example: Send email, update related entities, trigger notifications

  console.log('Created', result);

  // Your post-creation logic here`;
  }

  /**
   * Generate beforeUpdate specific logic
   */
  private generateBeforeUpdateBody(entity: string): string {
    return `  // Modify data before updating ${entity}
  // Example: Validate changes, update timestamps

  const modifiedData = { ...data };

  // Your modification logic here

  return modifiedData;`;
  }

  /**
   * Generate afterUpdate specific logic
   */
  private generateAfterUpdateBody(entity: string): string {
    return `  // Perform actions after ${entity} update
  // Example: Clear cache, log changes, trigger notifications

  console.log('Updated', result);

  // Your post-update logic here`;
  }

  /**
   * Generate beforeDelete specific logic
   */
  private generateBeforeDeleteBody(entity: string): string {
    return `  // Perform checks before deleting ${entity}
  // Example: Check dependencies, prevent deletion if referenced

  const canDelete = true; // Your logic here

  if (!canDelete) {
    throw new Error('Cannot delete ${entity}: still referenced');
  }`;
  }

  /**
   * Generate afterDelete specific logic
   */
  private generateAfterDeleteBody(entity: string): string {
    return `  // Perform cleanup after ${entity} deletion
  // Example: Delete related records, clear cache

  console.log('Deleted', result);

  // Your cleanup logic here`;
  }

  /**
   * Generate beforeRead specific logic
   */
  private generateBeforeReadBody(entity: string): string {
    return `  // Modify query or validate access before reading ${entity}
  // Example: Apply filters, check permissions, validate query parameters

  const modifiedQuery = { ...query };

  // Your modification logic here

  return modifiedQuery;`;
  }

  /**
   * Generate afterRead specific logic
   */
  private generateAfterReadBody(entity: string): string {
    return `  // Perform actions after reading ${entity}
  // Example: Transform data, enrich with related data, log access

  console.log('Read', result);

  // Your post-read logic here`;
  }

  /**
   * Generate beforeList specific logic
   */
  private generateBeforeListBody(entity: string): string {
    return `  // Modify query or validate before listing ${entity}
  // Example: Apply default filters, validate pagination, add sorting

  const modifiedQuery = { ...query };

  // Your modification logic here

  return modifiedQuery;`;
  }

  /**
   * Generate afterList specific logic
   */
  private generateAfterListBody(entity: string): string {
    return `  // Perform actions after listing ${entity}
  // Example: Validate each entity, transform data, apply business rules

  console.log('Listed', result.length, '${entity} records');

  // Your post-list logic here`;
  }

  /**
   * Generate validation specific logic
   */
  private generateValidationBody(entity: string): string {
    return `  // Validate ${entity} data
  // Example: Check required fields, validate formats, business rules

  const errors: string[] = [];

  // Your validation logic here
  // if (!data.field) {
  //   errors.push('field is required');
  // }

  return {
    valid: errors.length === 0,
    errors: errors.length > 0 ? errors : undefined,
  };`;
  }

  /**
   * Generate appropriate return statement
   */
  private generateReturnStatement(hookType: HookType, _entity: string): string {
    if (hookType.startsWith("before")) {
      if (hookType === "customValidate") {
        return "return validationResult;";
      }
      return "return modifiedData;";
    } else if (hookType.startsWith("after")) {
      return "// No return needed for after hooks";
    }
    return "";
  }

  /**
   * Get the data parameter name based on hook type
   */
  private getDataParameterName(hookType: HookType): string {
    if (hookType.startsWith("before")) {
      return "data";
    } else if (hookType.startsWith("after")) {
      return "result";
    } else if (hookType === "customValidate") {
      return "data";
    }
    return "input";
  }

  /**
   * Format hook name for display
   */
  private formatHookName(hookType: HookType): string {
    const words = hookType
      .replace(/([A-Z])/g, " $1")
      .trim()
      .split(" ");
    return words.map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
  }

  /**
   * Get execution description for hook
   */
  private getExecutionDescription(hookType: HookType): string {
    if (hookType.startsWith("before")) {
      return "before";
    } else if (hookType.startsWith("after")) {
      return "after";
    }
    return "during";
  }
}

/**
 * Create a new visitor instance with options
 */
export function createVisitor(options?: VisitorOptions): HookCodeGenerationVisitor {
  return new HookCodeGenerationVisitor(options);
}
